    sheet.getRange(`AF1:AF${weeks26.length}`).values = weeks26.map((v) => [v]);
  if (monthOrder.length > 0)
    sheet.getRange(`AG1:AG${monthOrder.length}`).values = monthOrder.map((v) => [v]);
  if (mw25List.length > 0)
    sheet.getRange(`AH1:AH${mw25List.length}`).values = mw25List.map((v) => [v]);
  if (mw26List.length > 0)
    sheet.getRange(`AI1:AI${mw26List.length}`).values = mw26List.map((v) => [v]);

  // ── Compute and write chart source data ───────────────────────────────────
  const weeklyRows = getWeeklyCompData(_compWeek25, _compWeek26, data);
  const monthlyRows = getMonthlyCompData(_compMonth, _compMonthWeek25, _compMonthWeek26, data);

  const wk25Lbl = _compWeek25 || "—";
